#include <stdio.h>

const char* podstring(const char* s1, const char* s2) {
	while (*s1 != '\0') {
		const char* p = s1;
		const char* q = s2;
		while (*p++ == *q++)
			if (*q == '\0') return s1;
		s1++;
	}
	return NULL;
}

int main() {
	char s1[100] = "testiranje"; 
	char s2[100] = "test";
	if (podstring(s1, s2))
		printf ("Podstring se nalazi u stringu.");
	else
		printf ("Podstring se ne nalazi u stringu.");
	return 0;
}
